export const BTN_IDS: Record<VehicleType, number[]> = {
  copter: [0, 2, 5, 3, 6, 9],
  plane: [0, 10, 11, 12, 19, 18, 17, 21, 20],
  rover: [0, 4, 10, 15, 11],
  sub: [0, 2, 16, 3, 4],
};

const _VTYPE_MAP: Record<number, VehicleType> = {
  2: 'copter',
  3: 'copter',
  4: 'copter',
  13: 'copter',
  14: 'copter',
  1: 'plane',
  19: 'plane',
  20: 'plane',
  21: 'plane',
  22: 'plane',
  23: 'plane',
  24: 'plane',
  25: 'plane',
  10: 'rover',
  12: 'sub',
};

export function vehicleType(mavTypeRaw: number): VehicleType {
  return _VTYPE_MAP[mavTypeRaw] ?? 'copter';
}

export function getModeName(vtype: VehicleType, modeId: number, locale: 'en' | 'zh' = 'en'): string {
  return MODE_TABLES[vtype]?.[modeId]?.[locale] ?? `MODE${modeId}`;
}

export function getModeCategory(vtype: VehicleType, modeId: number): ModeCategory {
  return MODE_TABLES[vtype]?.[modeId]?.category ?? 'assisted';
}

export function getModeButtons(vtype: VehicleType, locale: 'en' | 'zh' = 'en'): [number, string][] {
  const ids = BTN_IDS[vtype] ?? [];
  return ids.map((id) => [id, getModeName(vtype, id, locale)]);
}

export function getAllModes(vtype: VehicleType): { id: number; name: string; category: ModeCategory }[] {
  const table = MODE_TABLES[vtype] ?? {};
  return Object.entries(table)
    .map(([id, m]) => ({ id: Number(id), name: m.en, category: m.category }))
    .sort((a, b) => a.id - b.id);
}

export function getModeEntries(vtype: VehicleType): [number, string][] {
  const table = MODE_TABLES[vtype] ?? {};
  return Object.entries(table)
    .map(([id, m]) => [Number(id), m.en] as [number, string])
    .sort((a, b) => a[0] - b[0]);
}

